<div class="page-heading"><div><h2>Consulta de stock</h2><p>Existencias disponibles y alertas por producto.</p></div><a class="btn btn-success" href="index.php?route=reportes/inventario-excel"><i class="bi bi-file-earmark-excel"></i> Exportar Excel</a></div>
<form class="card border-0 shadow-sm mb-4" method="get"><input type="hidden" name="route" value="inventario/stock"><div class="card-body row g-3"><div class="col-md-5"><label class="form-label">Buscar</label><input class="form-control" name="q" value="<?=htmlspecialchars($filters['q'])?>" placeholder="Código, nombre o código de barras"></div><div class="col-md-3"><label class="form-label">Categoría</label><select class="form-select" name="categoria"><option value="0">Todas</option><?php foreach($categories as $c):?><option value="<?=(int)$c['IdCategoria']?>" <?=((int)$filters['categoria']===(int)$c['IdCategoria'])?'selected':''?>><?=htmlspecialchars($c['Nombre'])?></option><?php endforeach;?></select></div><div class="col-md-2"><label class="form-label">Estado</label><select class="form-select" name="estado"><option value="">Todos</option><option value="normal" <?=$filters['estado']==='normal'?'selected':''?>>Normal</option><option value="bajo" <?=$filters['estado']==='bajo'?'selected':''?>>Bajo mínimo</option><option value="agotado" <?=$filters['estado']==='agotado'?'selected':''?>>Agotado</option></select></div><div class="col-md-2 d-flex align-items-end"><button class="btn btn-primary w-100">Filtrar</button></div></div></form>
<div class="card border-0 shadow-sm"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Código</th><th>Producto</th><th>Categoría</th><th>Unidad</th><th class="text-end">Stock</th><th class="text-end">Mínimo</th><th class="text-end">Máximo</th><th>Estado</th></tr></thead><tbody><?php foreach($rows as $r): $badge=$r['EstadoStock']==='AGOTADO'?'danger':($r['EstadoStock']==='BAJO'?'warning':'success');?><tr><td><strong><?=htmlspecialchars($r['Codigo'])?></strong><small class="d-block text-muted"><?=htmlspecialchars((string)$r['CodigoBarras'])?></small></td><td><?=htmlspecialchars($r['Nombre'])?></td><td><?=htmlspecialchars($r['Categoria'])?></td><td><?=htmlspecialchars($r['Unidad'])?></td><td class="text-end fw-bold"><?=number_format((float)$r['StockActual'],2)?></td><td class="text-end"><?=number_format((float)$r['StockMinimo'],2)?></td><td class="text-end"><?=number_format((float)$r['StockMaximo'],2)?></td><td><span class="badge text-bg-<?=$badge?>"><?=htmlspecialchars($r['EstadoStock'])?></span></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="8" class="text-center py-5 text-muted">No existen productos para los filtros seleccionados.</td></tr><?php endif;?></tbody></table></div></div>
